import { Mail, Phone, MapPin, Send, ArrowRight } from 'lucide-react';

const Contact = () => {
    const [submitted, setSubmitted] = useState(false);
    const [loading, setLoading] = useState(false);

    const handleSubmit = (e) => {
        e.preventDefault();
        setLoading(true);
        setTimeout(() => {
            setLoading(false);
            setSubmitted(true);
        }, 1500);
    };

    return (
        <div className="bg-white">
            <PageHero
                title="Inquiries"
                subtitle="Formal correspondence and administrative support for the Alexandria community."
                image="https://images.unsplash.com/photo-1577563908411-5077b6dc7624?q=80&w=2070&auto=format&fit=crop"
            />

            <section className="section-padding">
                <div className="container-wide">
                    <div className="flex flex-col lg:flex-row gap-32 items-start">
                        {/* Contact Info */}
                        <motion.div
                            initial={{ opacity: 0, x: -50 }}
                            whileInView={{ opacity: 1, x: 0 }}
                            viewport={{ once: true }}
                            className="lg:w-5/12"
                        >
                            <span className="label-meta mb-6 block">Get in Touch</span>
                            <h2 className="text-huge text-dark mb-12 leading-[0.85] tracking-tighter">
                                Service & <br />
                                <span className="text-serif italic">Support.</span>
                            </h2>
                            <p className="text-xl text-dark/40 font-light leading-relaxed mb-16 font-sans">
                                Whether regarding admissions, academic progress, or community initiatives, our administration is here to facilitate your inquiry.
                            </p>

                            <div className="grid grid-cols-1 gap-12">
                                <div className="group border-b border-black/5 pb-10">
                                    <span className="text-primary font-bold text-[10px] uppercase tracking-[0.4em] mb-4 block">Visit Campus</span>
                                    <h4 className="text-2xl font-display font-bold text-dark mb-2">Alexandria, Eastern Cape</h4>
                                    <p className="text-sm text-dark/40 font-sans tracking-tight">Cnr Krog & Voortrekker Street, CBD, 6185</p>
                                </div>
                                <div className="group border-b border-black/5 pb-10">
                                    <span className="text-primary font-bold text-[10px] uppercase tracking-[0.4em] mb-4 block">Call Office</span>
                                    <h4 className="text-2xl font-display font-bold text-dark group-hover:text-primary transition-colors">+27 46 653 0126</h4>
                                </div>
                                <div className="group border-b border-black/5 pb-10">
                                    <span className="text-primary font-bold text-[10px] uppercase tracking-[0.4em] mb-4 block">Official Email</span>
                                    <h4 className="text-2xl font-display font-bold text-dark group-hover:text-primary transition-colors">alexandriahigh@telkomsa.net</h4>
                                </div>
                            </div>
                        </motion.div>

                        {/* Inquiry Form */}
                        <motion.div
                            initial={{ opacity: 0, y: 50 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            className="lg:w-7/12 relative bg-soft p-12 lg:p-20"
                        >
                            <AnimatePresence>
                                {submitted && (
                                    <motion.div
                                        initial={{ opacity: 0 }}
                                        animate={{ opacity: 1 }}
                                        exit={{ opacity: 0 }}
                                        className="absolute inset-0 z-20 bg-white flex flex-col items-center justify-center p-12 text-center"
                                    >
                                        <div className="w-20 h-20 border border-primary/20 flex items-center justify-center mb-8 text-primary">
                                            <Send size={32} />
                                        </div>
                                        <h3 className="text-3xl font-display font-bold text-dark mb-4 tracking-tighter uppercase">Message Sent</h3>
                                        <p className="text-dark/40 mb-12 font-light">Your inquiry has been logged. We will correspond shortly.</p>
                                        <button
                                            onClick={() => setSubmitted(false)}
                                            className="btn-studio btn-studio-primary bg-primary text-white"
                                        >
                                            Send Another
                                        </button>
                                    </motion.div>
                                )}
                            </AnimatePresence>

                            <h3 className="text-3xl font-display font-bold mb-16 text-dark tracking-tighter uppercase">Send an Inquiry</h3>
                            <form className="space-y-12" onSubmit={handleSubmit}>
                                <div className="grid md:grid-cols-2 gap-12">
                                    <div className="border-b border-black/10 flex flex-col gap-4 pb-4 focus-within:border-primary transition-colors">
                                        <label className="text-[10px] font-bold uppercase tracking-widest text-dark/30">First Name</label>
                                        <input required type="text" className="bg-transparent text-xl font-light outline-none" placeholder="First Name" />
                                    </div>
                                    <div className="border-b border-black/10 flex flex-col gap-4 pb-4 focus-within:border-primary transition-colors">
                                        <label className="text-[10px] font-bold uppercase tracking-widest text-dark/30">Last Name</label>
                                        <input required type="text" className="bg-transparent text-xl font-light outline-none" placeholder="Last Name" />
                                    </div>
                                </div>
                                <div className="border-b border-black/10 flex flex-col gap-4 pb-4 focus-within:border-primary transition-colors">
                                    <label className="text-[10px] font-bold uppercase tracking-widest text-dark/30">Email Address</label>
                                    <input required type="email" className="bg-transparent text-xl font-light outline-none" placeholder="email@address.com" />
                                </div>
                                <div className="border-b border-black/10 flex flex-col gap-4 pb-8 focus-within:border-primary transition-colors">
                                    <label className="text-[10px] font-bold uppercase tracking-widest text-dark/30">Message</label>
                                    <textarea required rows="4" className="bg-transparent text-xl font-light outline-none resize-none" placeholder="Nature of inquiry..."></textarea>
                                </div>
                                <button disabled={loading} type="submit" className="btn-studio btn-studio-primary bg-dark text-white flex items-center justify-center gap-6 group disabled:opacity-70 w-full lg:w-auto">
                                    {loading ? 'Processing...' : (
                                        <>Submit Inquiry <ArrowRight size={14} className="group-hover:translate-x-1 transition-transform" /></>
                                    )}
                                </button>
                            </form>
                        </motion.div>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default Contact;

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, CheckCircle, AlertCircle, Info, Phone } from 'lucide-react';

const CustomDialog = ({ isOpen, onClose, onConfirm, title, message, type = 'confirm', confirmText = 'Confirm', cancelText = 'Cancel' }) => {
    const handleConfirm = () => {
        if (onConfirm) onConfirm();
        onClose();
    };

    const getIcon = () => {
        switch (type) {
            case 'success':
                return <CheckCircle className="text-emerald-500" size={48} />;
            case 'error':
                return <AlertCircle className="text-rose-500" size={48} />;
            case 'info':
                return <Info className="text-blue-500" size={48} />;
            case 'phone':
                return <Phone className="text-blue-500" size={48} />;
            default:
                return <AlertCircle className="text-amber-500" size={48} />;
        }
    };

    const getAccentColor = () => {
        switch (type) {
            case 'success':
                return 'bg-emerald-500 hover:bg-emerald-600';
            case 'error':
                return 'bg-rose-500 hover:bg-rose-600';
            case 'info':
                return 'bg-blue-500 hover:bg-blue-600';
            case 'phone':
                return 'bg-blue-500 hover:bg-blue-600';
            default:
                return 'bg-primary hover:bg-primary/90';
        }
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[9999]"
                        onClick={type === 'alert' ? onClose : undefined}
                    />

                    {/* Dialog */}
                    <div className="fixed inset-0 flex items-center justify-center z-[10000] p-4">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 20 }}
                            transition={{ type: 'spring', duration: 0.3 }}
                            className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden"
                        >
                            {/* Header */}
                            <div className="relative bg-gradient-to-br from-slate-900 to-slate-800 p-6 text-center">
                                <div className="flex justify-center mb-4">
                                    {getIcon()}
                                </div>
                                {title && (
                                    <h3 className="text-xl font-black text-white uppercase tracking-wide">
                                        {title}
                                    </h3>
                                )}
                            </div>

                            {/* Content */}
                            <div className="p-6">
                                <p className="text-slate-700 text-center leading-relaxed whitespace-pre-line">
                                    {message}
                                </p>
                            </div>

                            {/* Actions */}
                            <div className="px-6 pb-6 flex gap-3">
                                {type !== 'alert' && (
                                    <button
                                        onClick={onClose}
                                        className="flex-1 py-3 px-4 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl font-bold uppercase text-sm tracking-wide transition-colors"
                                    >
                                        {cancelText}
                                    </button>
                                )}
                                <button
                                    onClick={handleConfirm}
                                    className={`flex-1 py-3 px-4 text-white rounded-xl font-bold uppercase text-sm tracking-wide transition-colors ${getAccentColor()}`}
                                >
                                    {confirmText}
                                </button>
                            </div>
                        </motion.div>
                    </div>
                </>
            )}
        </AnimatePresence>
    );
};

export default CustomDialog;

import React from 'react';
import { motion } from 'framer-motion';
import { Heart, HelpCircle, Edit3 } from 'lucide-react';

const FloatingMenu = () => {
    const items = [
        { icon: Edit3, label: 'Inquire', href: '/contact', color: 'text-primary' },
        { icon: HelpCircle, label: 'Help', href: '/about', color: 'text-primary' },
        { icon: Heart, label: 'Give', href: '/admission', color: 'text-primary' },
    ];

    return (
        <>
            {/* Desktop Side Menu */}
            <motion.div
                initial={{ opacity: 0, x: 50 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 1, duration: 0.5 }}
                className="fixed right-4 md:right-8 top-1/2 -translate-y-1/2 z-40 hidden md:flex flex-col gap-4"
            >
                {items.map((item, index) => (
                    <a
                        key={index}
                        href={item.href}
                        className="group relative flex items-center justify-center w-14 h-14 bg-white rounded-full shadow-lg hover:bg-primary hover:text-white transition-all duration-300 transform hover:scale-110"
                        aria-label={item.label}
                    >
                        <item.icon size={24} className={`transition-colors duration-300 ${item.color} group-hover:text-white`} />
                        <span className="absolute right-full mr-4 px-3 py-1 bg-white text-dark text-xs font-bold uppercase tracking-widest rounded shadow-md opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
                            {item.label}
                        </span>
                    </a>
                ))}
            </motion.div>

            {/* Mobile Bottom Bar */}
            <motion.div
                initial={{ opacity: 0, y: 50 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 1, duration: 0.5 }}
                className="fixed bottom-0 left-0 w-full z-40 flex md:hidden bg-white/90 backdrop-blur-xl border-t border-slate-100 shadow-[0_-10px_30px_rgba(0,0,0,0.05)] justify-around items-center px-4 py-3"
            >
                {items.map((item, index) => (
                    <a
                        key={index}
                        href={item.href}
                        className="flex flex-col items-center gap-1 group active:scale-90 transition-transform"
                    >
                        <div className={`p-2 rounded-xl transition-colors ${item.color} group-active:bg-primary/10`}>
                            <item.icon size={20} />
                        </div>
                        <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">
                            {item.label}
                        </span>
                    </a>
                ))}
            </motion.div>
        </>
    );
};

export default FloatingMenu;

