                        <div className="w-40 h-[1px] bg-white/5 relative overflow-hidden">
                            <motion.div
                                className="absolute inset-0 bg-accent origin-left"
                                initial={{ scaleX: 0 }}
                                animate={{ scaleX: 1 }}
                                key={currentSlide}
                                transition={{ duration: 12, ease: "linear" }}
                            />
