                                    <div className="w-6 h-px bg-primary/20" />
                                    <p className="text-[10px] font-bold uppercase tracking-[0.4em] text-dark/20">{stat.meta}</p>
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            </div>
        </section>
    );
};

