export default Login;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabaseClient';
import { Plus, Search, Filter, Edit2, Trash2, FileText, CheckCircle, Clock, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import NewsForm from '../../components/smt/NewsForm';
import CustomDialog from '../../components/CustomDialog';

const News = () => {
    const [news, setNews] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filterStatus, setFilterStatus] = useState('all');
    const [searchQuery, setSearchQuery] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingNews, setEditingNews] = useState(null);
    const [dialog, setDialog] = useState({ isOpen: false, type: 'confirm', title: '', message: '', onConfirm: null });

    const fetchNews = async () => {
        setLoading(true);
        let query = supabase
            .from('news')
            .select('*')
            .order('created_at', { ascending: false });

        if (filterStatus === 'published') {
            query = query.eq('is_published', true);
        } else if (filterStatus === 'draft') {
            query = query.eq('is_published', false);
        }

        if (searchQuery) {
            query = query.ilike('title', `%${searchQuery}%`);
        }

        const { data, error } = await query;
        if (error) console.error('Error fetching news:', error);
        else setNews(data || []);
        setLoading(false);
    };

    useEffect(() => {
        fetchNews();

        const channel = supabase
            .channel('smt-news')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'news' }, () => {
                fetchNews();
            })
            .subscribe();

        return () => supabase.removeChannel(channel);
    }, [filterStatus, searchQuery]);

    const handleEdit = (article) => {
        setEditingNews(article);
        setIsModalOpen(true);
    };

    const handleCreate = () => {
        setEditingNews(null);
        setIsModalOpen(true);
    };

    const handleModalClose = () => {
        setIsModalOpen(false);
        setEditingNews(null);
    };

    const handleFormSuccess = () => {
        handleModalClose();
        fetchNews();
    };

    const handleDelete = async (id) => {
        setDialog({
            isOpen: true,
            type: 'error',
            title: 'Delete Article',
            message: 'Are you sure you want to delete this article? This cannot be undone.',
            confirmText: 'Delete',
            cancelText: 'Cancel',
            onConfirm: async () => {
                const { error } = await supabase
                    .from('news')
                    .delete()
                    .eq('id', id);

                if (error) {
                    setDialog({
                        isOpen: true,
                        type: 'error',
                        title: 'Error',
                        message: 'Failed to delete article',
                        confirmText: 'OK',
                        onConfirm: null
                    });
                } else {
                    setDialog({
                        isOpen: true,
                        type: 'success',
                        title: 'Success',
                        message: 'Article deleted successfully',
                        confirmText: 'OK',
                        onConfirm: null
                    });
                    fetchNews();
                }
            }
        });
    };

    return (
        <div className="p-6 md:p-8 max-w-7xl mx-auto">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                <div>
                    <h1 className="text-2xl md:text-3xl font-display font-bold text-slate-900 uppercase tracking-widest">Newsroom</h1>
                    <p className="text-xs md:text-sm text-slate-500 font-medium mt-1 uppercase tracking-widest">Manage permanent stories and press releases.</p>
                </div>
                <button
                    onClick={handleCreate}
                    className="bg-primary text-white px-6 py-3 rounded-xl font-bold uppercase tracking-widest text-xs shadow-lg hover:bg-primary-dark transition-all flex items-center gap-2"
                >
                    <Plus size={16} />
                    New Article
                </button>
            </div>

            {/* Filters */}
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-8 flex flex-col md:flex-row gap-4 items-center">
                <div className="relative flex-1 w-full">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input
                        type="text"
                        placeholder="Search headlines..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary"
                    />
                </div>
                <div className="flex items-center gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
                    <Filter size={16} className="text-slate-400 shrink-0" />
                    {['all', 'published', 'draft'].map((status) => (
                        <button
                            key={status}
                            onClick={() => setFilterStatus(status)}
                            className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-widest whitespace-nowrap transition-colors ${filterStatus === status
                                ? 'bg-slate-800 text-white'
                                : 'bg-slate-50 text-slate-500 hover:bg-slate-100'
                                }`}
                        >
                            {status}
                        </button>
                    ))}
                </div>
            </div>

            {/* List */}
            <div className="space-y-4">
                {loading ? (
                    <div className="text-center py-12 text-slate-400 text-xs font-bold uppercase tracking-widest animate-pulse">
                        Loading News...
                    </div>
                ) : news.length === 0 ? (
                    <div className="text-center py-12 bg-white rounded-xl border border-slate-200 border-dashed">
                        <FileText size={48} className="mx-auto text-slate-200 mb-4" />
                        <h3 className="text-slate-900 font-bold mb-1">Newsroom Empty</h3>
                        <p className="text-slate-500 text-sm">Write your first article or promote a notice.</p>
                    </div>
                ) : (
                    <AnimatePresence>
                        {news.map((item) => (
                            <motion.div
                                key={item.id}
                                layout
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                                className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow group relative overflow-hidden"
                            >
                                <div className="flex flex-col md:flex-row gap-6 relative z-10">
                                    <div className="flex-1">
                                        <div className="flex items-start gap-4 mb-3">
                                            {item.is_published ? (
                                                <span className="px-2 py-1 rounded bg-emerald-100 text-emerald-700 text-[10px] font-bold uppercase tracking-widest border border-emerald-200 flex items-center gap-1">
                                                    <CheckCircle size={10} /> Published
                                                </span>
                                            ) : (
                                                <span className="px-2 py-1 rounded bg-slate-100 text-slate-600 text-[10px] font-bold uppercase tracking-widest border border-slate-200 flex items-center gap-1">
                                                    <Clock size={10} /> Draft
                                                </span>
                                            )}
                                            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">
                                                {new Date(item.published_at).toLocaleDateString()}
                                            </span>
                                        </div>
                                        <h3 className="text-xl font-display font-bold text-slate-900 mb-2">{item.title}</h3>
                                        <p className="text-slate-600 text-sm line-clamp-2 mb-4 font-medium">{item.summary}</p>
                                    </div>

                                    <div className="flex items-center gap-2 self-start md:self-center border-t md:border-t-0 md:border-l border-slate-100 pt-4 md:pt-0 md:pl-6 w-full md:w-auto justify-end">
                                        <button
                                            onClick={() => handleEdit(item)}
                                            className="p-2 text-slate-400 hover:text-primary hover:bg-slate-50 rounded-lg transition-colors"
                                            title="Edit Article"
                                        >
                                            <Edit2 size={18} />
                                        </button>
                                        <button
                                            onClick={() => handleDelete(item.id)}
                                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                            title="Delete Article"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </div>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                )}
            </div>

            {/* Modal */}
            <AnimatePresence>
                {isModalOpen && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={handleModalClose}
                            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
                        />
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 20 }}
                            className="bg-white w-full max-w-4xl rounded-2xl shadow-2xl relative z-10 overflow-hidden flex flex-col max-h-[90vh]"
                        >
                            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                                <div>
                                    <h2 className="text-2xl font-display font-bold text-slate-900">
                                        {editingNews ? 'Edit Story' : 'New Story'}
                                    </h2>
                                    <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                                        {editingNews ? 'Update existing content' : 'Create a new permanent record'}
                                    </p>
                                </div>
                                <button
                                    onClick={handleModalClose}
                                    className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                                >
                                    <X size={20} />
                                </button>
                            </div>

                            <div className="p-8 overflow-y-auto">
                                <NewsForm
                                    article={editingNews}
                                    onSuccess={handleFormSuccess}
                                    onCancel={handleModalClose}
                                />
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            <CustomDialog
                isOpen={dialog.isOpen}
                onClose={() => setDialog({ ...dialog, isOpen: false })}
                onConfirm={dialog.onConfirm}
                title={dialog.title}
                message={dialog.message}
                type={dialog.type}
                confirmText={dialog.confirmText}
                cancelText={dialog.cancelText}
            />
        </div>
    );
};

export default News;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabaseClient';
import { Plus, Search, Filter, Edit2, Archive, CheckCircle, Clock, FileText, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import NoticeForm from '../../components/smt/NoticeForm';
import NewsForm from '../../components/smt/NewsForm';
import CustomDialog from '../../components/CustomDialog';

const Notices = () => {
    const [notices, setNotices] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filterStatus, setFilterStatus] = useState('all');
    const [searchQuery, setSearchQuery] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingNotice, setEditingNotice] = useState(null);
    const [isPromoteModalOpen, setIsPromoteModalOpen] = useState(false);
    const [promotingNotice, setPromotingNotice] = useState(null);
    const [dialog, setDialog] = useState({ isOpen: false, type: 'confirm', title: '', message: '', onConfirm: null });

    const fetchNotices = async () => {
        setLoading(true);
        let query = supabase
            .from('notices')
            .select('*')
            .order('created_at', { ascending: false });

        if (filterStatus !== 'all') {
            query = query.eq('status', filterStatus);
        }

        if (searchQuery) {
            query = query.ilike('title', `%${searchQuery}%`);
        }

        const { data, error } = await query;
        if (error) console.error('Error fetching notices:', error);
        else setNotices(data || []);
        setLoading(false);
    };

    useEffect(() => {
        fetchNotices();

        const channel = supabase
            .channel('smt-notices')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'notices' }, () => {
                fetchNotices();
            })
            .subscribe();

        return () => supabase.removeChannel(channel);
    }, [filterStatus, searchQuery]); // Re-fetch when filters change

    const handleEdit = (notice) => {
        setEditingNotice(notice);
        setIsModalOpen(true);
    };

    const handleCreate = () => {
        setEditingNotice(null);
        setIsModalOpen(true);
    };

    const handleModalClose = () => {
        setIsModalOpen(false);
        setEditingNotice(null);
    };

    const handlePromote = (notice) => {
        setPromotingNotice(notice);
        setIsPromoteModalOpen(true);
    };

    const handlePromoteSuccess = () => {
        setIsPromoteModalOpen(false);
        setPromotingNotice(null);
        setDialog({
            isOpen: true,
            type: 'success',
            title: 'Success',
            message: 'Notice promoted to News Draft successfully!',
            confirmText: 'OK',
            onConfirm: null
        });
    };

    const handlePromoteClose = () => {
        setIsPromoteModalOpen(false);
        setPromotingNotice(null);
    };

    const handleFormSuccess = () => {
        handleModalClose();
        fetchNotices(); // Explicit refresh to be safe
    };

    const handleArchive = async (id) => {
        setDialog({
            isOpen: true,
            type: 'confirm',
            title: 'Archive Notice',
            message: 'Are you sure you want to archive this notice? It will no longer be visible to the public.',
            confirmText: 'Archive',
            cancelText: 'Cancel',
            onConfirm: async () => {
                const { error } = await supabase
                    .from('notices')
                    .update({ status: 'archived' })
                    .eq('id', id);

                if (error) {
                    setDialog({
                        isOpen: true,
                        type: 'error',
                        title: 'Error',
                        message: 'Failed to archive notice',
                        confirmText: 'OK',
                        onConfirm: null
                    });
                } else {
                    fetchNotices();
                    setDialog({
                        isOpen: true,
                        type: 'success',
                        title: 'Success',
                        message: 'Notice archived successfully',
                        confirmText: 'OK',
                        onConfirm: null
                    });
                }
            }
        });
    };

    const getStatusColor = (status) => {
        switch (status) {
            case 'active': return 'bg-emerald-100 text-emerald-700 border-emerald-200';
            case 'draft': return 'bg-slate-100 text-slate-700 border-slate-200';
            case 'archived': return 'bg-amber-50 text-amber-600 border-amber-100';
            default: return 'bg-slate-100 text-slate-600';
        }
    };

    return (
        <div className="p-6 md:p-8 max-w-7xl mx-auto">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                <div>
                    <h1 className="text-2xl md:text-3xl font-display font-bold text-slate-900 uppercase tracking-widest">Notices Board</h1>
                    <p className="text-xs md:text-sm text-slate-500 font-medium mt-1 uppercase tracking-widest">Manage ephemeral announcements and alerts.</p>
                </div>
                <button
                    onClick={handleCreate}
                    className="bg-primary text-white px-6 py-3 rounded-xl font-bold uppercase tracking-widest text-xs shadow-lg hover:bg-primary-dark transition-all flex items-center gap-2"
                >
                    <Plus size={16} />
                    New Notice
                </button>
            </div>

            {/* Filters */}
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-8 flex flex-col md:flex-row gap-4 items-center">
                <div className="relative flex-1 w-full">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input
                        type="text"
                        placeholder="Search notices..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary"
                    />
                </div>
                <div className="flex items-center gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
                    <Filter size={16} className="text-slate-400 shrink-0" />
                    {['all', 'active', 'draft', 'archived'].map((status) => (
                        <button
                            key={status}
                            onClick={() => setFilterStatus(status)}
                            className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-widest whitespace-nowrap transition-colors ${filterStatus === status
                                ? 'bg-slate-800 text-white'
                                : 'bg-slate-50 text-slate-500 hover:bg-slate-100'
                                }`}
                        >
                            {status}
                        </button>
                    ))}
                </div>
            </div>

            {/* List */}
            <div className="space-y-4">
                {loading ? (
                    <div className="text-center py-12 text-slate-400 text-xs font-bold uppercase tracking-widest animate-pulse">
                        Loading Notices...
                    </div>
                ) : notices.length === 0 ? (
                    <div className="text-center py-12 bg-white rounded-xl border border-slate-200 border-dashed">
                        <FileText size={48} className="mx-auto text-slate-200 mb-4" />
                        <h3 className="text-slate-900 font-bold mb-1">No Notices Found</h3>
                        <p className="text-slate-500 text-sm">Create a new notice to get started.</p>
                    </div>
                ) : (
                    <AnimatePresence>
                        {notices.map((notice) => (
                            <motion.div
                                key={notice.id}
                                layout
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                                className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow group relative overflow-hidden"
                            >
                                <div className="flex flex-col md:flex-row gap-6 relative z-10">
                                    <div className="flex-1">
                                        <div className="flex items-start gap-4 mb-2">
                                            <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase tracking-widest border ${getStatusColor(notice.status)}`}>
                                                {notice.status}
                                            </span>
                                            <span className="px-2 py-1 rounded bg-slate-100 text-slate-500 text-[10px] font-bold uppercase tracking-widest border border-slate-200">
                                                {notice.target_group}
                                            </span>
                                        </div>
                                        <h3 className="text-xl font-display font-bold text-slate-900 mb-2">{notice.title}</h3>
                                        <p className="text-slate-600 text-sm line-clamp-2 mb-4 font-medium">{notice.body}</p>

                                        <div className="flex items-center gap-6 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                                            <span className="flex items-center gap-1">
                                                <CheckCircle size={12} />
                                                Published: {new Date(notice.publish_at).toLocaleDateString()}
                                            </span>
                                            <span className="flex items-center gap-1 text-amber-500/80">
                                                <Clock size={12} />
                                                Expires: {new Date(notice.expire_at).toLocaleDateString()}
                                            </span>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-2 self-start md:self-center border-t md:border-t-0 md:border-l border-slate-100 pt-4 md:pt-0 md:pl-6 w-full md:w-auto justify-end">
                                        <button
                                            onClick={() => handlePromote(notice)}
                                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                            title="Promote to News"
                                        >
                                            <FileText size={18} />
                                        </button>
                                        <button
                                            onClick={() => handleEdit(notice)}
                                            className="p-2 text-slate-400 hover:text-primary hover:bg-slate-50 rounded-lg transition-colors"
                                            title="Edit Notice"
                                        >
                                            <Edit2 size={18} />
                                        </button>
                                        {notice.status !== 'archived' && (
                                            <button
                                                onClick={() => handleArchive(notice.id)}
                                                className="p-2 text-slate-400 hover:text-amber-600 hover:bg-amber-50 rounded-lg transition-colors"
                                                title="Archive Notice"
                                            >
                                                <Archive size={18} />
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                )}
            </div>

            {/* Modal */}
            <AnimatePresence>
                {isModalOpen && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={handleModalClose}
                            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
                        />
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 20 }}
                            className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl relative z-10 overflow-hidden flex flex-col max-h-[90vh]"
                        >
                            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                                <div>
                                    <h2 className="text-xl font-display font-bold text-slate-900">
                                        {editingNotice ? 'Edit Notice' : 'New Notice'}
                                    </h2>
                                    <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                                        {editingNotice ? 'Modify existing announcement' : 'Create a new announcement'}
                                    </p>
                                </div>
                                <button
                                    onClick={handleModalClose}
                                    className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                                >
                                    <X size={20} />
                                </button>
                            </div>

                            <div className="p-6 overflow-y-auto">
                                <NoticeForm
                                    notice={editingNotice}
                                    onSuccess={handleFormSuccess}
                                    onCancel={handleModalClose}
                                />
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
            {/* Promote Modal */}
            <AnimatePresence>
                {isPromoteModalOpen && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={handlePromoteClose}
                            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
                        />
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 20 }}
                            className="bg-white w-full max-w-4xl rounded-2xl shadow-2xl relative z-10 overflow-hidden flex flex-col max-h-[90vh]"
                        >
                            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-purple-50/50">
                                <div>
                                    <h2 className="text-xl font-display font-bold text-purple-900">
                                        Promote to News
                                    </h2>
                                    <p className="text-xs text-purple-600/70 font-bold uppercase tracking-widest mt-1">
                                        Converting notice to permanent record
                                    </p>
                                </div>
                                <button
                                    onClick={handlePromoteClose}
                                    className="p-2 hover:bg-purple-100 rounded-full text-purple-400 hover:text-purple-600 transition-colors"
                                >
                                    <X size={20} />
                                </button>
                            </div>

                            <div className="p-8 overflow-y-auto">
                                <NewsForm
                                    article={{
                                        title: promotingNotice?.title,
                                        content: promotingNotice?.body,
                                        summary: promotingNotice?.body.substring(0, 250), // Auto-generate summary
                                        is_published: false // Draft by default
                                    }}
                                    onSuccess={handlePromoteSuccess}
                                    onCancel={handlePromoteClose}
                                />
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
            <CustomDialog
                isOpen={dialog.isOpen}
                onClose={() => setDialog({ ...dialog, isOpen: false })}
                onConfirm={dialog.onConfirm}
                title={dialog.title}
                message={dialog.message}
                type={dialog.type}
                confirmText={dialog.confirmText}
                cancelText={dialog.cancelText}
            />
        </div >
    );
};

export default Notices;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabaseClient';
import { Plus, Trash2, Save, Image as ImageIcon, Loader2 } from 'lucide-react';

const WebsiteManagement = () => {
    const [slides, setSlides] = useState([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [newSlide, setNewSlide] = useState({
        image: '',
        tag: '',
        title: '',
        styledtitle: '',
        desc: ''
    });

    useEffect(() => {
        fetchSlides();
    }, []);

    const fetchSlides = async () => {
        try {
            const { data, error } = await supabase
                .from('hero_slides')
                .select('*')
                .order('created_at', { ascending: true });

            if (error) throw error;
            setSlides(data || []);
        } catch (error) {
            console.error('Error fetching slides:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleAddSlide = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            const { data, error } = await supabase
                .from('hero_slides')
                .insert([newSlide])
                .select();

            if (error) throw error;

            setSlides([...slides, data[0]]);
            setSlides([...slides, data[0]]);
            setNewSlide({ image: '', tag: '', title: '', styledtitle: '', desc: '' });
        } catch (error) {
            console.error('Error adding slide:', error);
            alert('Failed to add slide');
        } finally {
            setSaving(false);
        }
    };

    const handleDeleteSlide = async (id) => {
        if (!confirm('Are you sure you want to delete this slide?')) return;

        try {
            const { error } = await supabase
                .from('hero_slides')
                .delete()
                .eq('id', id);

            if (error) throw error;
            setSlides(slides.filter(slide => slide.id !== id));
        } catch (error) {
            console.error('Error deleting slide:', error);
            alert('Failed to delete slide');
        }
    };

    const handleUpdateSlide = async (id, field, value) => {
        // Optimistic update
        const updatedSlides = slides.map(slide =>
            slide.id === id ? { ...slide, [field]: value } : slide
        );
        setSlides(updatedSlides);

        // Debounced save could be implemented here, but for now simple update
        // In a real app we might want a "Save" button for edits or auto-save

        // checking if we should save to DB immediately or wait for explicit save
        // For this UI, let's just update local state and have a "Save Changes" button?
        // Or specific "Update" action.
        // Let's go with immediate update for simplicity in this iteration.

        try {
            const { error } = await supabase
                .from('hero_slides')
                .update({ [field]: value })
                .eq('id', id);

            if (error) throw error;
        } catch (error) {
            console.error('Error updating slide:', error);
            // Revert on error?
        }
    };

    if (loading) return (
        <div className="flex items-center justify-center min-h-[400px]">
            <Loader2 size={32} className="animate-spin text-primary" />
        </div>
    );

    return (
        <div className="p-8 max-w-7xl mx-auto">
            <header className="mb-12">
                <h1 className="text-3xl font-display font-bold text-slate-800 mb-2">Website Management</h1>
                <p className="text-slate-500">Manage the Hero section content and visuals.</p>
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                {/* Add New Slide Form */}
                <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm h-fit">
                    <h2 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                        <Plus size={20} className="text-primary" />
                        Add New Slide
                    </h2>

                    <form onSubmit={handleAddSlide} className="space-y-6">
                        <div>
                            <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-2">Image URL</label>
                            <input
                                type="text"
                                value={newSlide.image}
                                onChange={e => setNewSlide({ ...newSlide, image: e.target.value })}
                                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-primary/50 transition-colors"
                                placeholder="https://..."
                                required
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-2">Tag</label>
                                <input
                                    type="text"
                                    value={newSlide.tag}
                                    onChange={e => setNewSlide({ ...newSlide, tag: e.target.value })}
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-primary/50 transition-colors"
                                    placeholder="e.g. Admissions"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-2">Main Title</label>
                                <input
                                    type="text"
                                    value={newSlide.title}
                                    onChange={e => setNewSlide({ ...newSlide, title: e.target.value })}
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-primary/50 transition-colors"
                                    placeholder="e.g. Dignity"
                                    required
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-2">Styled Title</label>
                                <input
                                    type="text"
                                    value={newSlide.styledtitle}
                                    onChange={e => setNewSlide({ ...newSlide, styledtitle: e.target.value })}
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-primary/50 transition-colors"
                                    placeholder="e.g. Refined."
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-2">Description</label>
                            <textarea
                                value={newSlide.desc}
                                onChange={e => setNewSlide({ ...newSlide, desc: e.target.value })}
                                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-primary/50 transition-colors h-24 resize-none"
                                placeholder="Short description..."
                                required
                            />
                        </div>

                        <button
                            type="submit"
                            disabled={saving}
                            className="w-full py-4 bg-primary text-white font-bold uppercase tracking-widest rounded-lg hover:bg-primary-bright transition-colors disabled:opacity-50"
                        >
                            {saving ? 'Saving...' : 'Add Slide'}
                        </button>
                    </form>
                </div>

                {/* Existing Slides List */}
                <div className="space-y-6">
                    <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                        <ImageIcon size={20} className="text-slate-400" />
                        Active Slides
                    </h2>

                    {slides.length === 0 ? (
                        <div className="p-12 text-center border-2 border-dashed border-slate-200 rounded-xl">
                            <p className="text-slate-400">No slides configured yet.</p>
                        </div>
                    ) : (
                        slides.map((slide) => (
                            <div key={slide.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm group">
                                <div className="flex gap-6">
                                    <div className="w-32 h-32 shrink-0 bg-slate-100 rounded-lg overflow-hidden relative">
                                        <img src={slide.image} alt={slide.title} className="w-full h-full object-cover" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-start justify-between mb-4">
                                            <div>
                                                <span className="text-[10px] font-bold uppercase tracking-widest text-primary mb-1 block">
                                                    {slide.tag}
                                                </span>
                                                <h3 className="text-xl font-bold text-slate-800 truncate">
                                                    {slide.title} <span className="font-serif italic font-normal text-slate-400">{slide.styledtitle}</span>
                                                </h3>
                                            </div>
                                            <button
                                                onClick={() => handleDeleteSlide(slide.id)}
                                                className="p-2 text-slate-400 hover:text-red-500 transition-colors"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                        <p className="text-sm text-slate-500 line-clamp-2">
                                            {slide.desc}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>
        </div>
    );
};

export default WebsiteManagement;
